def now_ms() -> int:
    return int(time.time() * 1000)

def clamp(v: float, lo: float, hi: float) -> float:
    return lo if v < lo else hi if v > hi else v

def vec_len2(x: float, y: float, z: float) -> float:
    return x*x + y*y + z*z

def normalize_yaw(yaw: float) -> float:
    yaw = yaw % 360.0
    if yaw < 0:
        yaw += 360.0
    return yaw

